const GREEN = '#A3E851';
const BLUE_TINT = 'rgba(70,155,192,0.08)';
const NAVY_TINT = 'rgba(5,4,46,0.06)';

const STAGES = ['Booked', 'Collected', 'Received', 'Booking In', 'All Assets Booked', 'Processing/Pricing', 'Complete'];

function MetricRow({ label, value, highlight, prefix, tileColor }) {
  return (
    <div style={{
      display: 'flex', justifyContent: 'space-between', alignItems: 'center',
      padding: '5px 6px', borderRadius: '6px', marginBottom: '3px',
      background: tileColor || '#f8fafc',
    }}>
