        fontSize: '12px', fontWeight: 700, fontFamily: FONT,
        color: highlight ? (parseFloat(value) < 0 ? '#dc2626' : NAVY) : NAVY
      }}>
        {prefix || ''}{typeof value === 'number' ? value.toLocaleString('en-GB', { minimumFractionDigits: value % 1 !== 0 ? 2 : 0 }) : value}
      </span>
    </div>
  );
}

function SectionHeader({ title, color }) {
  return (
    <div style={{
      fontSize: '10px', fontWeight: 700, color: color || '#64748b',
      textTransform: 'uppercase', letterSpacing: '0.08em', fontFamily: FONT,
      padding: '3px 6px', borderRadius: '4px',
      background: color ? color + '18' : '#f1f5f9',
      marginBottom: '4px', marginTop: '8px'
    }}>{title}</div>
  );
}

function App() {
  const [model, setModel] = React.useState({...appsmith.model});
  const [loading, setLoading] = React.useState(false);

  React.useEffect(() => {
    const unsub = appsmith.onModelChange((newModel) => {
      setModel({ ...newModel });
      setLoading(false);
    });
    return () => typeof unsub === 'function' && unsub();
  }, []);

  const current = model.current_status;
