  const progress = currentIndex >= 0 ? Math.round(((currentIndex + 1) / STAGES.length) * 100) : 0;
  const s = typeof model.summary === 'string' ? JSON.parse(model.summary) : (model.summary || {});

  const gp = (parseFloat(s.sales_total) || 0)
    - (parseFloat(s.sales_fees) || 0)
    - (parseFloat(s.total_cost) || 0)
    - (parseFloat(s.parts_cost) || 0)
    - (parseFloat(s.carriage_cost) || 0);

  React.useEffect(() => {
    if (next !== model.next_status) {
      appsmith.updateModel({ next_status: next });
    }
  }, [next]);

  const advance = () => {
    if (!next) return;
    setLoading(true);
    appsmith.triggerEvent('onAdvanceStatus');
  };

  return (
    <div style={{ fontFamily: FONT, display: 'flex', flexDirection: 'row', gap: '0', alignItems: 'flex-start', width: '100%', boxSizing: 'border-box', overflow: 'hidden' }}>

      {/* LEFT */}
      <div style={{
        display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '10px',
        flex: '1 1 0', minWidth: 0, paddingRight: '12px',
        borderRight: `1px solid rgba(70,155,192,0.2)`, boxSizing: 'border-box'
      }}>
        <div style={{ position: 'relative', width: '110px', height: '110px' }}>
          <svg width="110" height="110" viewBox="0 0 140 140">
            <circle cx="70" cy="70" r="60" fill="none" stroke="#e5e7eb" strokeWidth="10" />
            <circle
              cx="70" cy="70" r="60" fill="none"
              stroke={BLUE} strokeWidth="10"
              strokeDasharray={`${(progress / 100) * 377} 377`}
              strokeLinecap="round"
              transform="rotate(-90 70 70)"
            />
          </svg>
          <div style={{
            position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
            display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center'
          }}>
            <div style={{ fontSize: '18px', fontWeight: 700, color: NAVY, fontFamily: FONT }}>{progress}%</div>
            <div style={{ fontSize: '10px', color: '#6b7280', fontFamily: FONT }}>complete</div>
          </div>
        </div>

        <div style={{ width: '100%', display: 'flex', flexDirection: 'column', gap: '3px' }}>
          {STAGES.map((stage, i) => {
            const isDone = i < currentIndex;
            const isCurrent = i === currentIndex;
            return (
              <div key={stage} style={{
                display: 'flex', alignItems: 'center', gap: '7px',
                padding: '5px 8px', borderRadius: '6px',
                background: isCurrent ? BLUE_TINT : (isDone ? '#f9fafb' : 'transparent'),
                border: isCurrent ? `1px solid ${BLUE}` : '1px solid transparent',
                boxSizing: 'border-box'
              }}>
                <div style={{
                  width: '16px', height: '16px', borderRadius: '50%', flexShrink: 0,
                  background: isDone ? BLUE : (isCurrent ? '#fff' : '#e5e7eb'),
                  border: isCurrent ? `2px solid ${BLUE}` : 'none',
                  display: 'flex', alignItems: 'center', justifyContent: 'center'
                }}>
                  {isDone && <span style={{ fontSize: '10px', color: '#fff' }}>✓</span>}
                </div>
                <span style={{
                  fontSize: '11px', fontFamily: FONT,
                  fontWeight: isCurrent ? 600 : 400,
                  color: isDone ? BLUE : isCurrent ? NAVY : '#9ca3af'
                }}>{stage}</span>
              </div>
            );
          })}
        </div>

