        <div style={{
          fontSize: '10px', fontWeight: 700, color: NAVY, fontFamily: FONT,
          textTransform: 'uppercase', letterSpacing: '0.08em',
          marginBottom: '8px', paddingBottom: '5px',
          borderBottom: `2px solid ${BLUE_TINT}`
        }}>
          Collection Summary
        </div>

        <SectionHeader title="Units" color={BLUE} />
        <MetricRow label="Expected" value={s.expected_units || 0} tileColor={BLUE_TINT} />
        <MetricRow label="Received" value={s.received || 0} tileColor={BLUE_TINT} />
        <MetricRow label="Available for Sale" value={s.available_for_sale || 0} tileColor={BLUE_TINT} />
        <MetricRow label="Sold" value={s.sold_count || 0} tileColor={BLUE_TINT} />
        <MetricRow label="Recycled" value={s.recycled || 0} tileColor={BLUE_TINT} />

        <SectionHeader title="Financials" color={NAVY} />
        <MetricRow label="Sales" value={parseFloat(s.sales_total) || 0} prefix="£" highlight tileColor={NAVY_TINT} />
        <MetricRow label="Sales Fees" value={parseFloat(s.sales_fees) || 0} prefix="£" tileColor="#fef9ee" />
        <MetricRow label="Cost" value={parseFloat(s.total_cost) || 0} prefix="£" tileColor="#fef9ee" />
        <MetricRow label="Parts" value={parseFloat(s.parts_cost) || 0} prefix="£" tileColor="#fef9ee" />
        <MetricRow label="Carriage" value={parseFloat(s.carriage_cost) || 0} prefix="£" tileColor="#fef9ee" />

        <div style={{
          display: 'flex', justifyContent: 'space-between', alignItems: 'center',
          padding: '7px 8px', marginTop: '5px', borderRadius: '8px',
          background: gp < 0 ? '#fee2e2' : BLUE_TINT,
          border: `1px solid ${gp < 0 ? '#fca5a5' : BLUE}`,
          boxSizing: 'border-box'
        }}>
          <span style={{ fontSize: '12px', fontWeight: 700, color: gp < 0 ? '#dc2626' : NAVY, fontFamily: FONT }}>Gross Profit</span>
          <span style={{ fontSize: '13px', fontWeight: 800, color: gp < 0 ? '#dc2626' : NAVY, fontFamily: FONT }}>
            £{gp.toLocaleString('en-GB', { minimumFractionDigits: 2 })}
          </span>
        </div>
      </div>

    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
